(function () {
  const input = document.getElementById('search-input');
  const type = document.getElementById('search-type');
  const year = document.getElementById('search-year');
  const button = document.getElementById('search-button');
  const results = document.getElementById('search-results');

  function normalize(value) {
    return String(value || '').trim().toLowerCase();
  }

  function card(item) {
    const tags = Array.isArray(item.tags) ? item.tags.join(' ') : '';
    return `
<a class="movie-card" href="${item.url}">
  <span class="poster">
    <img src="${item.cover}" alt="${item.title}" loading="lazy">
    <span class="poster-type">${item.type || '影视'}</span>
    <span class="poster-play">▶</span>
  </span>
  <span class="movie-card-body">
    <strong>${item.title}</strong>
    <em>${item.oneLine || tags}</em>
    <small>${item.year || ''} · ${item.region || ''}</small>
    <small>${item.genre || ''}</small>
  </span>
</a>`;
  }

  function render() {
    const keyword = normalize(input && input.value);
    const selectedType = normalize(type && type.value);
    const selectedYear = normalize(year && year.value);
    let matched = siteSearchData.filter(function (item) {
      const text = normalize([
        item.title,
        item.region,
        item.type,
        item.year,
        item.genre,
        item.oneLine,
        Array.isArray(item.tags) ? item.tags.join(' ') : ''
      ].join(' '));
      const byKeyword = !keyword || text.includes(keyword);
      const byType = !selectedType || normalize(item.type) === selectedType;
      const byYear = !selectedYear || normalize(item.year) === selectedYear;
      return byKeyword && byType && byYear;
    });

    matched = matched.slice(0, 60);
    if (!matched.length) {
      results.innerHTML = '<div class="info-card"><h2>暂无匹配影片</h2><p>可以尝试更换关键词、类型或年份继续搜索。</p></div>';
      return;
    }

    results.innerHTML = '<div class="movie-grid">' + matched.map(card).join('') + '</div>';
  }

  if (button) {
    button.addEventListener('click', render);
  }

  [input, type, year].forEach(function (element) {
    if (element) {
      element.addEventListener('input', render);
      element.addEventListener('change', render);
    }
  });
})();
